CustomField.formula:
/*IF( ISBLANK(Line_Item_Block_Description__c) && ISBLANK(Line_Item_Block__c) && isRemoved__c=false , 0, 1)*/
/* Join all fields to look for characters, and trim whitespace then see if field is marked as removed*/
IF ( LEN( TRIM( Billing_Block_Code__c & Billing_Block_Description__c & Delivery_Block_Code__c & Delivery_Block_Description__c & Line_Item_Block__c & Line_Item_Block_Description__c ))=0 && isRemoved__c=false , 0, 1)
